//! # Chaos Service — Adaptive Coordination Engine
//!
//! Separate process providing intelligent sweep triggering using chaos engine
//! for pattern analysis and anomaly detection. Communicates with aeon-monitor
//! and sweep-service via IPC for coordinated operation.

use distributed_inference::pleromatic_frame::PleromaticFrame;
use serde::{Deserialize, Serialize};
use std::env;

// --- Service Identification ---

#[derive(Debug, Clone)]
pub struct ServiceId {
    pub monitor_id: String,
    pub hub_id: String,
    pub service_type: String,
}

impl ServiceId {
    fn new(monitor_id: &str, hub_id: &str, service_type: &str) -> Self {
        Self {
            monitor_id: monitor_id.to_string(),
            hub_id: hub_id.to_string(),
            service_type: service_type.to_string(),
        }
    }

    fn socket_path(&self) -> String {
        format!(
            "/tmp/chaos-service-{}-{}.sock",
            self.monitor_id, self.hub_id
        )
    }

    fn from_env() -> Self {
        let monitor_id = env::var("AEON_MONITOR_ID").unwrap_or_else(|_| "default".to_string());
        let hub_id = env::var("AEON_HUB_ID").unwrap_or_else(|_| "hub-0".to_string());
        Self::new(&monitor_id, &hub_id, "chaos")
    }
}
use std::collections::{HashMap, VecDeque};
use std::io::{self, Read, Write};
use std::os::unix::net::{UnixListener, UnixStream};
use std::path::Path;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::{Duration, SystemTime, UNIX_EPOCH};

// --- Adaptive Coordination Structures ---

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TriggerDecision {
    pub timestamp_ms: u64,
    pub should_trigger: bool,
    pub trigger_type: TriggerType,
    pub confidence: f32,
    pub analysis_summary: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum TriggerType {
    BaselineInterval,  // Regular systematic sweep
    NewSignalDetected, // Unprecedented frequency pattern
    CoverageGap,       // Missing data in frequency grid
    AnomalyDetected,   // Unusual pattern identified
    ManualRequest,     // Explicit user request
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PatternAnalysis {
    pub timestamp_ms: u64,
    pub signal_count: u32,
    pub active_frequencies: Vec<u64>,
    pub novelty_score: f32,
    pub complexity_score: f32,
    pub anomaly_indicators: Vec<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum IpcMessage {
    Frame(PleromaticFrame),
    PatternAnalysisRequest,
    PatternAnalysisResult(PatternAnalysis),
    TriggerCommand(TriggerCommand),
    TriggerDecision(TriggerDecision),
    Ping,
    Pong,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TriggerCommand {
    pub command_type: TriggerType,
    pub priority: u8, // 0=low, 1=medium, 2=high, 3=urgent
    pub parameters: HashMap<String, String>,
}

// --- Simplified Chaos Engine ---

struct SimpleChaosEngine {
    agent_count: u32,
    _energy_distribution: u64,
    _weyl_state: u64,
}

impl SimpleChaosEngine {
    fn new(agent_count: u32, energy_distribution: u64) -> Self {
        Self {
            agent_count,
            _energy_distribution: energy_distribution,
            _weyl_state: SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap()
                .as_nanos() as u64,
        }
    }

    fn agent_count(&self) -> u32 {
        self.agent_count
    }
}

// --- Chaos Service Core ---

struct ChaosService {
    service_id: ServiceId,
    chaos_engine: SimpleChaosEngine,
    ipc_listener: UnixListener,
    frame_buffer: VecDeque<PleromaticFrame>,
    _pattern_history: VecDeque<PatternAnalysis>,
    last_trigger_time: Option<SystemTime>,
    baseline_interval_ms: u64,
}

impl ChaosService {
    fn new(service_id: ServiceId) -> io::Result<Self> {
        let socket_path = service_id.socket_path();

        // Remove existing socket file if it exists
        if Path::new(&socket_path).exists() {
            std::fs::remove_file(&socket_path)?;
        }

        let ipc_listener = UnixListener::bind(&socket_path)?;

        // Initialize simplified chaos engine
        let chaos_engine = SimpleChaosEngine::new(1000, 1000);

        Ok(Self {
            service_id,
            chaos_engine,
            ipc_listener,
            frame_buffer: VecDeque::with_capacity(1000),
            _pattern_history: VecDeque::with_capacity(60),
            last_trigger_time: None,
            baseline_interval_ms: 10000, // 10 seconds
        })
    }

    fn run(&mut self) -> io::Result<()> {
        println!("[CHAOS-SERVICE] Started adaptive coordination engine");
        println!(
            "[CHAOS-SERVICE] Service ID: {}-{}",
            self.service_id.monitor_id, self.service_id.hub_id
        );
        println!(
            "[CHAOS-SERVICE] Chaos engine: {} agents",
            self.chaos_engine.agent_count()
        );
        println!(
            "[CHAOS-SERVICE] Baseline interval: {}ms",
            self.baseline_interval_ms
        );
        println!("[CHAOS-SERVICE] Socket: {}", self.service_id.socket_path());
        println!("[CHAOS-SERVICE] Listening for IPC connections...");

        // Move frame_buffer into Arc for sharing between threads
        let frame_buffer_shared = Arc::new(Mutex::new(std::mem::take(&mut self.frame_buffer)));
        let buffer_analysis = Arc::clone(&frame_buffer_shared);

        thread::spawn(move || {
            loop {
                thread::sleep(Duration::from_millis(1000)); // Analyze every second

                let mut buffer = buffer_analysis.lock().unwrap();
                if !buffer.is_empty() {
                    // Create manifold input from frames
                    let frames: Vec<PleromaticFrame> = buffer.iter().cloned().collect();
                    buffer.clear();

                    // Perform pattern analysis
                    let analysis = analyze_frame_patterns(&frames);
                    println!(
                        "[CHAOS-SERVICE] Pattern analysis: {} signals, {:.3} novelty",
                        analysis.signal_count, analysis.novelty_score
                    );
                }
            }
        });

        // Background trigger thread
        let trigger_interval = self.baseline_interval_ms;
        let last_trigger = Arc::new(Mutex::new(std::mem::take(&mut self.last_trigger_time)));
        let trigger_shared = Arc::clone(&last_trigger);

        thread::spawn(move || {
            loop {
                thread::sleep(Duration::from_millis(5000)); // Check every 5 seconds

                let mut last = trigger_shared.lock().unwrap();
                let now = SystemTime::now();

                let should_trigger = match *last {
                    None => true,
                    Some(last_time) => {
                        if let Ok(elapsed) = now.duration_since(last_time) {
                            elapsed.as_millis() as u64 >= trigger_interval
                        } else {
                            true
                        }
                    }
                };

                if should_trigger {
                    *last = Some(now);
                    println!("[CHAOS-SERVICE] Baseline trigger activated");
                    // In a real implementation, this would send a trigger command to sweep-service
                }
            }
        });

        // Main IPC loop
        let listener = std::mem::replace(
            &mut self.ipc_listener,
            UnixListener::bind("/tmp/dummy.sock").unwrap(),
        );
        for stream in listener.incoming() {
            match stream {
                Ok(stream) => {
                    if let Err(e) = self.handle_client(stream, &frame_buffer_shared) {
                        eprintln!("[CHAOS-SERVICE] Error handling client: {}", e);
                    }
                }
                Err(e) => {
                    eprintln!("[CHAOS-SERVICE] Connection error: {}", e);
                }
            }
        }

        Ok(())
    }

    fn handle_client(
        &mut self,
        mut stream: UnixStream,
        frame_buffer_shared: &Arc<Mutex<VecDeque<PleromaticFrame>>>,
    ) -> io::Result<()> {
        println!("[CHAOS-SERVICE] Client connected");

        loop {
            // Read message length first (4 bytes)
            let mut len_bytes = [0u8; 4];
            if stream.read_exact(&mut len_bytes).is_err() {
                break; // Client disconnected
            }

            let len = u32::from_le_bytes(len_bytes) as usize;
            if len > 1_000_000 {
                // 1MB limit
                eprintln!("[CHAOS-SERVICE] Message too large: {} bytes", len);
                break;
            }

            // Read message
            let mut buffer = vec![0u8; len];
            if stream.read_exact(&mut buffer).is_err() {
                break;
            }

            // Deserialize message
            let message: IpcMessage = bincode::deserialize(&buffer)
                .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;

            match message {
                IpcMessage::Frame(frame) => {
                    let mut buffer = frame_buffer_shared.lock().unwrap();
                    buffer.push_back(frame);

                    // Limit buffer size
                    while buffer.len() > 1000 {
                        buffer.pop_front();
                    }
                }
                IpcMessage::PatternAnalysisRequest => {
                    let analysis = self.perform_pattern_analysis(frame_buffer_shared);
                    let response = IpcMessage::PatternAnalysisResult(analysis);
                    let response_data = bincode::serialize(&response).unwrap();
                    let response_len = (response_data.len() as u32).to_le_bytes();

                    stream.write_all(&response_len)?;
                    stream.write_all(&response_data)?;
                }
                IpcMessage::TriggerCommand(command) => {
                    self.handle_trigger_command(command);
                }
                IpcMessage::Ping => {
                    let response = IpcMessage::Pong;
                    let response_data = bincode::serialize(&response).unwrap();
                    let response_len = (response_data.len() as u32).to_le_bytes();

                    stream.write_all(&response_len)?;
                    stream.write_all(&response_data)?;
                }
                _ => {
                    eprintln!("[CHAOS-SERVICE] Unexpected message type");
                }
            }
        }

        println!("[CHAOS-SERVICE] Client disconnected");
        Ok(())
    }

    fn perform_pattern_analysis(
        &self,
        frame_buffer_shared: &Arc<Mutex<VecDeque<PleromaticFrame>>>,
    ) -> PatternAnalysis {
        let buffer = frame_buffer_shared.lock().unwrap();
        let frames: Vec<PleromaticFrame> = buffer.iter().cloned().collect();

        if frames.is_empty() {
            return PatternAnalysis {
                timestamp_ms: SystemTime::now()
                    .duration_since(UNIX_EPOCH)
                    .unwrap()
                    .as_millis() as u64,
                signal_count: 0,
                active_frequencies: Vec::new(),
                novelty_score: 0.0,
                complexity_score: 0.0,
                anomaly_indicators: Vec::new(),
            };
        }

        analyze_frame_patterns(&frames)
    }

    fn handle_trigger_command(&mut self, command: TriggerCommand) {
        println!(
            "[CHAOS-SERVICE] Received trigger command: {:?}",
            command.command_type
        );

        // In a real implementation, this would forward the command to sweep-service
        match command.command_type {
            TriggerType::BaselineInterval => {
                println!("[CHAOS-SERVICE] Baseline sweep triggered");
            }
            TriggerType::NewSignalDetected => {
                println!("[CHAOS-SERVICE] High-resolution sweep for new signal");
            }
            TriggerType::CoverageGap => {
                println!("[CHAOS-SERVICE] Compensatory sweep for coverage gap");
            }
            TriggerType::AnomalyDetected => {
                println!("[CHAOS-SERVICE] Anomaly investigation sweep");
            }
            TriggerType::ManualRequest => {
                println!("[CHAOS-SERVICE] Manual sweep request");
            }
        }
    }
}

// --- Pattern Analysis Functions ---

fn analyze_frame_patterns(frames: &[PleromaticFrame]) -> PatternAnalysis {
    let timestamp_ms = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_millis() as u64;

    // Count different signal types
    let mut signal_count = 0;
    let mut active_frequencies = Vec::new();
    let mut anomaly_indicators = Vec::new();

    // Analyze spectrogram frames for frequency patterns
    for frame in frames {
        if frame.is_spectrogram_waterfall() {
            signal_count += 1;

            // Extract frequency information
            if let Some(center_hz_str) = frame.attributes.get("rf_center_hz") {
                if let Ok(center_hz) = center_hz_str.parse::<u64>() {
                    if !active_frequencies.contains(&center_hz) {
                        active_frequencies.push(center_hz);
                    }
                }
            }

            // Check for anomalies
            if frame.data.len() > 1000 {
                anomaly_indicators.push("Large spectrogram data".to_string());
            }
        }
    }

    // Calculate novelty score based on new frequencies
    let novelty_score = if active_frequencies.len() > 10 {
        0.8 // High novelty
    } else if active_frequencies.len() > 5 {
        0.5 // Medium novelty
    } else if !active_frequencies.is_empty() {
        0.2 // Low novelty
    } else {
        0.0 // No novelty
    };

    // Calculate complexity score
    let complexity_score = (frames.len() as f32 / 100.0).min(1.0);

    PatternAnalysis {
        timestamp_ms,
        signal_count,
        active_frequencies,
        novelty_score,
        complexity_score,
        anomaly_indicators,
    }
}

// --- Main Function ---

fn main() -> io::Result<()> {
    let service_id = ServiceId::from_env();

    println!("[CHAOS-SERVICE] Starting adaptive coordination service...");
    println!("[CHAOS-SERVICE] Monitor ID: {}", service_id.monitor_id);
    println!("[CHAOS-SERVICE] Hub ID: {}", service_id.hub_id);
    println!("[CHAOS-SERVICE] Socket path: {}", service_id.socket_path());

    let mut service = ChaosService::new(service_id)?;
    service.run()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_pattern_analysis_empty() {
        let frames = Vec::new();
        let analysis = analyze_frame_patterns(&frames);

        assert_eq!(analysis.signal_count, 0);
        assert_eq!(analysis.active_frequencies.len(), 0);
        assert_eq!(analysis.novelty_score, 0.0);
        assert_eq!(analysis.complexity_score, 0.0);
    }

    #[test]
    fn test_trigger_decision_serialization() {
        let decision = TriggerDecision {
            timestamp_ms: 1234567890,
            should_trigger: true,
            trigger_type: TriggerType::NewSignalDetected,
            confidence: 0.85,
            analysis_summary: "Test analysis".to_string(),
        };

        let serialized = bincode::serialize(&decision).unwrap();
        let deserialized: TriggerDecision = bincode::deserialize(&serialized).unwrap();

        assert_eq!(decision.timestamp_ms, deserialized.timestamp_ms);
        assert_eq!(decision.should_trigger, deserialized.should_trigger);
        match deserialized.trigger_type {
            TriggerType::NewSignalDetected => {} // Expected
            _ => panic!("Wrong trigger type"),
        }
        assert_eq!(decision.confidence, deserialized.confidence);
    }

    #[test]
    fn test_ipc_message_serialization() {
        let message = IpcMessage::Ping;
        let serialized = bincode::serialize(&message).unwrap();
        let deserialized: IpcMessage = bincode::deserialize(&serialized).unwrap();

        match deserialized {
            IpcMessage::Ping => {} // Expected
            _ => panic!("Deserialized message mismatch"),
        }
    }

    #[test]
    fn test_trigger_command_creation() {
        let command = TriggerCommand {
            command_type: TriggerType::CoverageGap,
            priority: 2,
            parameters: HashMap::from([
                ("frequency_range".to_string(), "100M-200M".to_string()),
                ("resolution".to_string(), "high".to_string()),
            ]),
        };

        match command.command_type {
            TriggerType::CoverageGap => {} // Expected
            _ => panic!("Wrong command type"),
        }
        assert_eq!(command.priority, 2);
        assert_eq!(command.parameters.len(), 2);
    }
}
